public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // в”Ђв”Ђ Fish: Construction & Inherited getters в”Ђв”Ђ
        try {
            Fish nemo = new Fish("Nemo", "Finding Nemo", "Just keep swimming!",
                                "coral reef", true);
            check("Fish inherits getName()",
                  "Nemo", nemo.getName());
        } catch (Exception e) { fail("Fish inherits getName()", e); }

        try {
            Fish nemo = new Fish("Nemo", "Finding Nemo", "Just keep swimming!",
                                "coral reef", true);
            check("Fish inherits getMovie()",
                  "Finding Nemo", nemo.getMovie());
        } catch (Exception e) { fail("Fish inherits getMovie()", e); }

        try {
            Fish nemo = new Fish("Nemo", "Finding Nemo", "Just keep swimming!",
                                "coral reef", true);
            check("Fish inherits getCatchphrase()",
                  "Just keep swimming!", nemo.getCatchphrase());
        } catch (Exception e) { fail("Fish inherits getCatchphrase()", e); }

        // в”Ђв”Ђ Fish: New getters в”Ђв”Ђ
        try {
            Fish dory = new Fish("Dory", "Finding Nemo", "I shall call him Squishy",
                                "open ocean", true);
            check("Fish.getHabitat()",
                  "open ocean", dory.getHabitat());
        } catch (Exception e) { fail("Fish.getHabitat()", e); }

        try {
            Fish dory = new Fish("Dory", "Finding Nemo", "I shall call him Squishy",
                                "open ocean", true);
            check("Fish.getCanTalk()",
                  "true", String.valueOf(dory.getCanTalk()));
        } catch (Exception e) { fail("Fish.getCanTalk()", e); }

        // в”Ђв”Ђ Fish: swim() and describe() в”Ђв”Ђ
        try {
            Fish nemo = new Fish("Nemo", "Finding Nemo", "Just keep swimming!",
                                "coral reef", true);
            check("Fish.swim()",
                  "Nemo swims through the coral reef!", nemo.swim());
        } catch (Exception e) { fail("Fish.swim()", e); }

        try {
            Fish nemo = new Fish("Nemo", "Finding Nemo", "Just keep swimming!",
                                "coral reef", true);
            check("Fish.describe()",
                  "Nemo is a fish from Finding Nemo. Habitat: coral reef. Can talk: true",
                  nemo.describe());
        } catch (Exception e) { fail("Fish.describe()", e); }

        // в”Ђв”Ђ Emotion: Construction & Inherited getters в”Ђв”Ђ
        try {
            Emotion joy = new Emotion("Joy", "Inside Out", "Think positive!",
                                     "yellow", 9);
            check("Emotion inherits getName()",
                  "Joy", joy.getName());
        } catch (Exception e) { fail("Emotion inherits getName()", e); }

        try {
            Emotion joy = new Emotion("Joy", "Inside Out", "Think positive!",
                                     "yellow", 9);
            check("Emotion inherits getMovie()",
                  "Inside Out", joy.getMovie());
        } catch (Exception e) { fail("Emotion inherits getMovie()", e); }

        // в”Ђв”Ђ Emotion: New getters в”Ђв”Ђ
        try {
            Emotion anger = new Emotion("Anger", "Inside Out", "Congratulations, San Francisco!",
                                       "red", 8);
            check("Emotion.getColor()",
                  "red", anger.getColor());
        } catch (Exception e) { fail("Emotion.getColor()", e); }

        try {
            Emotion anger = new Emotion("Anger", "Inside Out", "Congratulations, San Francisco!",
                                       "red", 8);
            check("Emotion.getIntensity()",
                  "8", String.valueOf(anger.getIntensity()));
        } catch (Exception e) { fail("Emotion.getIntensity()", e); }

        // в”Ђв”Ђ Emotion: feel() в”Ђв”Ђ
        try {
            Emotion joy = new Emotion("Joy", "Inside Out", "Think positive!",
                                     "yellow", 9);
            check("Emotion.feel()",
                  "Joy radiates yellow energy at intensity 9!",
                  joy.feel());
        } catch (Exception e) { fail("Emotion.feel()", e); }

        // в”Ђв”Ђ Inheritance structure checks в”Ђв”Ђ
        try {
            Fish f = new Fish("Nemo", "Finding Nemo", "Just keep swimming!",
                             "coral reef", true);
            check("Fish instanceof PixarCharacter",
                  "true", String.valueOf(f instanceof PixarCharacter));
        } catch (Exception e) { fail("Fish instanceof PixarCharacter", e); }

        try {
            Emotion e2 = new Emotion("Joy", "Inside Out", "Think positive!",
                                    "yellow", 9);
            check("Emotion instanceof PixarCharacter",
                  "true", String.valueOf(e2 instanceof PixarCharacter));
        } catch (Exception e) { fail("Emotion instanceof PixarCharacter", e); }

        // в”Ђв”Ђ Encapsulation checks в”Ђв”Ђ
        try {
            java.lang.reflect.Field f = Fish.class.getDeclaredField("habitat");
            check("Fish.habitat is private",
                  "true", String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Fish.habitat field exists", new Exception("Field 'habitat' not found in Fish"));
        } catch (Exception e) { fail("Fish.habitat is private", e); }

        try {
            java.lang.reflect.Field f = Emotion.class.getDeclaredField("color");
            check("Emotion.color is private",
                  "true", String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Emotion.color field exists", new Exception("Field 'color' not found in Emotion"));
        } catch (Exception e) { fail("Emotion.color is private", e); }

        try {
            java.lang.reflect.Field f = Emotion.class.getDeclaredField("intensity");
            check("Emotion.intensity is private",
                  "true", String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Emotion.intensity field exists", new Exception("Field 'intensity' not found in Emotion"));
        } catch (Exception e) { fail("Emotion.intensity is private", e); }
    }

    // в”Ђв”Ђ Helpers в”Ђв”Ђ
    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " вЂ” expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " вЂ” " + e.getMessage()); failed++;
    }
}
